previewCss:
.darma-loader-darma-custom-124 {
  color: var(--loader-color, #059669);
width: 49px;
aspect-ratio: 1;
--c: no-repeat linear-gradient(currentColor calc(50% - 10px),#0000 0 calc(50% + 10px),currentColor 0);
background:
var(--c) 0% 100%,
var(--c) 50% 100%,
var(--c) 100% 100%;
background-size: 20% calc(200% + 20px);
animation:darma-loader-darma-custom-124-l4 1s infinite linear;
}
@keyframes darma-loader-darma-custom-124-l4 {
33% {background-position: 0% 50%,50% 100%,100% 100%}
50% {background-position: 0% 0%,50% 50%,100% 100%}
66% {background-position: 0% 0%,50% 0%,100% 50%}
100% {background-position: 0% 0%,50% 0%,100% 0%}
}

